import axios from 'axios';

const isBrowser = typeof window !== 'undefined';
const isLocalHost = isBrowser && ['localhost', '127.0.0.1'].includes(window.location.hostname);
const configuredApiUrl = String(process.env.REACT_APP_API_URL || '').trim();
const fallbackProductionApiUrl = '/api';
const fallbackLocalApiUrl = 'http://localhost:3001';

const api = axios.create({
  baseURL: configuredApiUrl || (isLocalHost ? fallbackLocalApiUrl : fallbackProductionApiUrl),
  timeout: 60000
});

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');

  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }

  return config;
});

export const apiBaseUrl = api.defaults.baseURL;

api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (typeof window !== 'undefined' && error.response?.status === 401) {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
    }

    if (process.env.NODE_ENV !== 'production') {
      // Helps debug silent API failures during local validation and CI logs.
      console.error('[api]', error.config?.method?.toUpperCase(), error.config?.url, error.response?.status, error.response?.data || error.message);
    }

    return Promise.reject(error);
  }
);

export default api;
