import React from 'react';
import { Routes, Route } from 'react-router-dom';

import Login from './Login';
import Home from './HomeShellFixed';
import Cadastro from './Cadastro';
import Dashboard from './Dashboard';
import DashboardManagement from './DashboardManagement';
import BI from './BI';
import Register from './Register';
import Profile from './Profile';
import ComplaintDetail from './ComplaintDetail';
import MarketingIntake from './MarketingIntakePage';
import NpsSurveyPage from './NpsSurveyPage';
import NpsManagement from './NpsManagement';
import NpsDashboard from './NpsDashboard';
import AdminPanel from './AdminPanel';
import PatientManagement from './PatientManagementPage';
import { ProtectedRoute, PublicOnlyRoute, RouteFallback } from './ProtectedRoute';
import './App.css';

function App() {
  return (
    <Routes>
      <Route path="/" element={<PublicOnlyRoute><Login /></PublicOnlyRoute>} />
      <Route path="/primeiro-cadastro" element={<Register />} />
      <Route path="/marketing" element={<MarketingIntake />} />
      <Route path="/registro-marketing" element={<MarketingIntake />} />
      <Route path="/pesquisa-nps" element={<NpsSurveyPage />} />
      <Route path="/home" element={<ProtectedRoute><Home /></ProtectedRoute>} />
      <Route path="/cadastro" element={<ProtectedRoute><Cadastro /></ProtectedRoute>} />
      <Route path="/gestao" element={<ProtectedRoute><DashboardManagement /></ProtectedRoute>} />
      <Route path="/gestao/:id" element={<ProtectedRoute><ComplaintDetail /></ProtectedRoute>} />
      <Route path="/dashboard" element={<ProtectedRoute><Dashboard /></ProtectedRoute>} />
      <Route path="/bi" element={<ProtectedRoute><BI /></ProtectedRoute>} />
      <Route path="/perfil" element={<ProtectedRoute><Profile /></ProtectedRoute>} />
      <Route path="/gestao-nps" element={<ProtectedRoute><NpsManagement /></ProtectedRoute>} />
      <Route path="/dashboard-nps" element={<ProtectedRoute><NpsDashboard /></ProtectedRoute>} />
      <Route path="/admin" element={<ProtectedRoute><AdminPanel /></ProtectedRoute>} />
      <Route path="/pacientes" element={<ProtectedRoute><PatientManagement /></ProtectedRoute>} />
      <Route path="/pacientes/cadastro" element={<ProtectedRoute><PatientManagement /></ProtectedRoute>} />
      <Route path="/pacientes/dashboard" element={<ProtectedRoute><PatientManagement /></ProtectedRoute>} />
      <Route path="*" element={<RouteFallback />} />
    </Routes>
  );
}

export default App;
