import React from 'react';
import { Navigate, Outlet, useLocation } from 'react-router-dom';
import { readUser } from './constants';

function clearSession() {
  localStorage.removeItem('token');
  localStorage.removeItem('user');
}

function decodeJwtPayload(token) {
  try {
    const payloadSegment = String(token || '').split('.')[1];

    if (!payloadSegment) {
      return null;
    }

    const normalized = payloadSegment.replace(/-/g, '+').replace(/_/g, '/');
    const padded = normalized.padEnd(Math.ceil(normalized.length / 4) * 4, '=');
    return JSON.parse(window.atob(padded));
  } catch (error) {
    return null;
  }
}

export function hasSession() {
  const token = localStorage.getItem('token');
  const user = readUser();
  const normalizedToken = String(token || '').trim();
  const payload = normalizedToken ? decodeJwtPayload(normalizedToken) : null;

  if (normalizedToken && payload?.exp && (payload.exp * 1000) <= Date.now()) {
    clearSession();
    return false;
  }

  if (normalizedToken && !payload) {
    clearSession();
    return false;
  }

  return Boolean(
    normalizedToken
    && normalizedToken !== 'undefined'
    && normalizedToken !== 'null'
    && (user?.id || user?.email)
  );
}

export function ProtectedRoute({ children = null }) {
  const location = useLocation();

  if (!hasSession()) {
    return <Navigate to="/" replace state={{ from: location.pathname + location.search }} />;
  }

  return children || <Outlet />;
}

export function PublicOnlyRoute({ children = null }) {
  if (hasSession()) {
    return <Navigate to="/home" replace />;
  }

  return children || <Outlet />;
}

export function RouteFallback() {
  return <Navigate to={hasSession() ? '/home' : '/'} replace />;
}
